# Function to check if a function is log-concave
is_log_concave <- function(f, x_min, x_max, n_points = 100) {
  x <- seq(x_min, x_max, length.out = n_points)
  y <- f(x)
  if (any(is.na(y))) return(FALSE)

  # Check if the second derivative is non-positive
  # We approximate the second derivative using finite differences
  dy <- diff(y)
  d2y <- diff(dy)

  # Check if the second derivative is non-positive
  if (any(d2y > 0)) {
    return(FALSE)
  }

  return(TRUE)
}

